/** BR DDD 41: números locais → 55 + dígitos (API sem @s.whatsapp.net). */
const digits = [
  '4137982599','4137982908','4137982960','4137982595','4137981318','4137981306',
  '4137981158','4137981130','4137980902','4137984981','4137984966','4137984019','4137984061'
];
const toApiNumber = (d) => '55' + String(d).replace(/\D/g, '');
const variants = [
  'Olá! Tudo bem? Mensagem de teste n8n.',
  'Oi — campanha diagnóstico. Pode ignorar.',
  '[TESTE] disparo verificado pela fila UAZAPI.',
  'Mensagem aleatória A — Leads Infinitos.',
  'Mensagem aleatória B — verificação de envio.',
  'Oi! Conteúdo randômico para diff entre destinos.',
  'Campanha lab: texto variado por destinatário.'
];
const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];
const messages = digits.map((d, i) => ({
  number: toApiNumber(d),
  type: 'text',
  text: `${pick(variants)} (#${i + 1} · ${Math.random().toString(36).slice(2, 9)})`,
}));
return [{
  json: {
    delayMin: 3,
    delayMax: 8,
    info: `n8n-diag-advanced-${Date.now()}`,
    scheduled_for: 1,
    messages,
  }
}];

const create = $('Criar campanha advanced').first().json;
const folderId = create.folder_id ?? create.folderId ?? null;
const items = $input.all();
let folders = [];
const j0 = items[0]?.json;
if (Array.isArray(j0)) {
  folders = j0;
} else {
  for (const it of items) {
    const j = it.json;
    if (j && j.id) folders.push(j);
  }
}
const found = folderId ? folders.find((f) => f.id === folderId) : null;
return [{
  json: {
    folder_id_from_create: folderId,
    create_full_response: create,
    folder_found_in_listfolders: !!found,
    folder_row_from_api: found ?? null,
    total_folders_in_response: folders.length,
    ids_sample: folders.slice(0, 12).map((f) => f.id),
  },
}];
